+using Microsoft.Extensions.AI;
+using OpenAI;
+
+// --- Tool implementations ---
+
+var notebook = new Notebook();
+
+[Description("Search the web for information on a query. Returns a list of result snippets.")]
+string WebSearch([Description("The search query")] string query)
+{
+    Console.WriteLine($"  🔍 Searching: \"{query}\"");
+
+    // Simulated web search results keyed on topic keywords
+    var results = new List<string>();
+
+    var q = query.ToLowerInvariant();
+
+    if (q.Contains("quantum computing"))
+    {
+        results.AddRange([
+            "Quantum computing uses qubits that can exist in superposition, enabling parallel computation. " +
+            "Major players include IBM, Google, and Microsoft. IBM's Condor processor reached 1,121 qubits in 2023.",
+            "Google achieved quantum supremacy in 2019 with their Sycamore processor, completing a task in 200 seconds " +
+            "that would take classical supercomputers 10,000 years.",
+            "Microsoft is pursuing topological qubits for better error correction. Their Azure Quantum platform " +
+            "provides cloud access to quantum hardware from multiple vendors.",
+        ]);
+    }
+
+    if (q.Contains("application") || q.Contains("use case") || q.Contains("usage"))
+    {
+        results.AddRange([
+            "Key applications of quantum computing include drug discovery, cryptography, optimization problems, " +
+            "financial modeling, and materials science.",
+            "Quantum machine learning could exponentially speed up training of AI models. " +
+            "Quantum sensors may revolutionize medical imaging and navigation.",
+        ]);
+    }
+
+    if (q.Contains("challenge") || q.Contains("limitation") || q.Contains("problem"))
+    {
+        results.AddRange([
+            "Major challenges include qubit decoherence, error rates, and the need for extremely low temperatures " +
+            "(near absolute zero) for most current quantum computers.",
+            "Quantum error correction requires many physical qubits per logical qubit, making large-scale " +
+            "fault-tolerant quantum computing still years away.",
+        ]);
+    }
+
+    if (results.Count == 0)
+    {
+        results.Add($"General information about '{query}': This is an active area of research with many recent developments. " +
+            "Try more specific queries for detailed results.");
+    }
+
+    return JsonSerializer.Serialize(results);
+}
+
+[Description("Save a note to the research notebook. Use this to record important findings.")]
+string SaveNote(
+    [Description("A short title for the note")] string title,
+    [Description("The content of the note")] string content)
+{
+    notebook.AddNote(title, content);
+    Console.WriteLine($"  📝 Note saved: \"{title}\"");
+    return $"Note '{title}' saved successfully. You now have {notebook.Count} note(s).";
+}
+
+[Description("Retrieve all saved research notes.")]
+string GetNotes()
+{
+    Console.WriteLine("  📖 Reading notes...");
+    return notebook.Count == 0
+        ? "No notes saved yet."
+        : JsonSerializer.Serialize(notebook.GetAllNotes());
+}
+
+// --- Agent setup ---
+
+var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? "no-key";
+var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";
+
+IChatClient client = new OpenAIClient(apiKey)
+    .GetChatClient(model)
+    .AsIChatClient()
+    .AsBuilder()
+    .UseFunctionInvocation()
+    .Build();
+
+var tools = new[]
+{
+    AIFunctionFactory.Create(WebSearch),
+    AIFunctionFactory.Create(SaveNote),
+    AIFunctionFactory.Create(GetNotes),
+};
+
+var chatOptions = new ChatOptions { Tools = [.. tools] };
+
+var topic = args.Length > 0 ? string.Join(' ', args) : "quantum computing";
+
+Console.WriteLine($"🔬 Research Agent Starting...");
+Console.WriteLine($"📋 Topic: {topic}");
+Console.WriteLine(new string('─', 50));
+
+var messages = new List<ChatMessage>
+{
+    new(ChatRole.System,
+        """
+        You are a research agent. Your job is to research a given topic thoroughly by:
+        1. Searching the web for information (make at least 3 different searches)
+        2. Saving important findings as notes using the note-taking tool
+        3. After gathering enough information, retrieving all your notes and writing a comprehensive summary
+
+        Be thorough: search for overview information, specific applications/use cases, and
+        current challenges or limitations. Save notes as you discover key findings.
+        End with a final summary of all your research.
+        """),
+    new(ChatRole.User, $"Please research the following topic and provide a comprehensive summary: {topic}"),
+};
+
+// Agent loop
+Console.WriteLine();
+var response = await client.GetResponseAsync(messages, chatOptions);
+Console.WriteLine();
+Console.WriteLine(new string('─', 50));
+Console.WriteLine("📄 RESEARCH SUMMARY");
+Console.WriteLine(new string('─', 50));
+Console.WriteLine(response.Text);
+Console.WriteLine(new string('─', 50));
+Console.WriteLine($"📊 Total notes collected: {notebook.Count}");
+
+// --- Notebook class ---
+
+class Notebook
+{
+    private readonly List<(string Title, string Content, DateTime Timestamp)> _notes = [];
+
+    public int Count => _notes.Count;
+
+    public void AddNote(string title, string content)
+        => _notes.Add((title, content, DateTime.UtcNow));
+
+    public List<object> GetAllNotes()
+        => _notes.Select(n => (object)new { n.Title, n.Content, n.Timestamp }).ToList();
+}
